  async updateProduct(id: number, data: Partial<OdooProduct>): Promise<boolean> {
    return await callOdoo<boolean>({
      model: 'product.product',
      method: 'write',
      args: [[id], data],
    });
  },

  async archiveProduct(id: number): Promise<boolean> {
    return await callOdoo<boolean>({
      model: 'product.product',
      method: 'write',
      args: [[id], { active: false }],
